+                  })}>
+                    <Download size={13} />
+                    <span>PNG</span>
+                  </button>
+                </div>
+              )}
+            </div>
+          </div>
+        ))}
+        {busy && (
+          <div className="timeline-row reasoning">
+            <div className="timeline-marker"><Loader2 size={12} /></div>
+            <div className="timeline-card working">
+              <div className="timeline-title"><span>{t.workingTitle}</span></div>
+              <div className="timeline-detail">{t.working}</div>
+            </div>
+          </div>
+        )}
+      </section>
+
+      <section className="composer">
+        <div className="composer-actions" aria-label={t.quickTasks}>
+          {actions.map((action) => (
+            <button className="task-button" disabled={busy || !modelReady} key={action.label} onClick={() => runTask(action.task)}>
